import type { DefaultAuthentication } from "typeorm/driver/sqlserver/authentication/DefaultAuthentication.js";
import type { AzureActiveDirectoryAccessTokenAuthentication } from "typeorm/driver/sqlserver/authentication/AzureActiveDirectoryAccessTokenAuthentication.js";
import type { AzureActiveDirectoryDefaultAuthentication } from "typeorm/driver/sqlserver/authentication/AzureActiveDirectoryDefaultAuthentication.js";
import type { AzureActiveDirectoryMsiAppServiceAuthentication } from "typeorm/driver/sqlserver/authentication/AzureActiveDirectoryMsiAppServiceAuthentication.js";
import type { AzureActiveDirectoryMsiVmAuthentication } from "typeorm/driver/sqlserver/authentication/AzureActiveDirectoryMsiVmAuthentication.js";
import type { AzureActiveDirectoryPasswordAuthentication } from "typeorm/driver/sqlserver/authentication/AzureActiveDirectoryPasswordAuthentication.js";
import type { AzureActiveDirectoryServicePrincipalSecret } from "typeorm/driver/sqlserver/authentication/AzureActiveDirectoryServicePrincipalSecret.js";
import type { NtlmAuthentication } from "typeorm/driver/sqlserver/authentication/NtlmAuthentication.js";
export type SqlServerConnectionCredentialsAuthenticationOptions = DefaultAuthentication | NtlmAuthentication | AzureActiveDirectoryAccessTokenAuthentication | AzureActiveDirectoryDefaultAuthentication | AzureActiveDirectoryMsiAppServiceAuthentication | AzureActiveDirectoryMsiVmAuthentication | AzureActiveDirectoryPasswordAuthentication | AzureActiveDirectoryServicePrincipalSecret;
/**
 * SqlServer specific connection credential options.
 */
export interface SqlServerConnectionCredentialsOptions {
    /**
     * Connection url where the connection is performed.
     */
    readonly url?: string;
    /**
     * Database host.
     */
    readonly host?: string;
    /**
     * Database host port.
     */
    readonly port?: number;
    /**
     * Database name to connect to.
     */
    readonly database?: string;
    /**
     * Database username.
     */
    readonly username?: string;
    /**
     * Database password.
     */
    readonly password?: string;
    /**
     * Authentication settings
     * It overrides username and password, when passed.
     */
    readonly authentication?: SqlServerConnectionCredentialsAuthenticationOptions;
}
